public:
    void valueChanged(bool changed = true) override;
    int notificationCount() const;

private:
    int m_notifications = 0;
};

struct RollbackObservation {
    int notificationsAfterSecondBinding;
    int notificationsAfterRollback;
};

// ============================================
// Function implementation
// ============================================

RollbackObservation test_observer_state_rollback() {
    // 1. Create RecordingNode instances
    RecordingNode sensor1, sensor2;

    // 2. Get observer graph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Register nodes
    observerGraph.registerNode(&sensor1);
    observerGraph.registerNode(&sensor2);

    // 4. Set up initial dependency
    // Bind sensor1 to sensor2: when sensor1 changes, sensor2 gets notified
    sensor1.addOneObserver(&sensor2);

    // 5. Save node state for rollback
    // Save current observer state of sensor2
    auto originalObservers = sensor2.getObservers();

    // 6. Replace dependencies transactionally
    // Clear current observers and set up new dependency
    sensor2.resetObservers();
    // Create a new sensor for the second binding
    RecordingNode sensor3;
    observerGraph.registerNode(&sensor3);
    sensor2.addOneObserver(&sensor3);

    // 7. Trigger notification on second sensor (sensor2)
    // This will notify sensor3 due to the new binding
    sensor2.valueChanged(true);

    // 8. Record notification count after second binding
    int notificationsAfterSecondBinding = sensor3.notificationCount();

    // 9. Execute rollback
    // Restore original observer state
    sensor2.resetObservers();
    for (const auto& observer : originalObservers) {
        sensor2.addOneObserver(observer);
    }

    // 10. Trigger notification on first sensor (sensor1)
    // This will notify sensor2 due to the original binding
    sensor1.valueChanged(true);

    // 11. Record notification count after rollback
    int notificationsAfterRollback = sensor2.notificationCount();

    // 12. Return notification counts
    return RollbackObservation{
        notificationsAfterSecondBinding,
        notificationsAfterRollback
    };
}

}  // namespace test_reaction
